    {
        var data = GenerateReport();

        // File() sets Content-Type and Content-Disposition automatically.
        // No need for Response.Clear(), AddHeader(), Write(), or End().
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv");
    }

