    // Response.Redirect(url, true) called Thread.Abort to stop execution
    // after the redirect header was set. In ASP.NET Core, returning a
    // RedirectResult ends the action naturally — no abort, no exception.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block is removed entirely:
        // ASP.NET Core redirects never throw. OperationCanceledException
        // is the modern equivalent if you need to handle client disconnects
        // (propagated via HttpContext.RequestAborted).
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

